use strict;
use warnings;
use PDF::API2;
use PDF::TableExtract;

# function to extract metadata
sub extract_metadata {
    my $pdf = PDF::API2->open(shift);
    my $info = $pdf->info;

    my $author = $info->Author;
    my $title = $info->Title;
    my $date = $info->ModDate;

    return ($author, $title, $date);
}

# function to extract tables
sub extract_tables {
    my $filename = shift;
    my $te = PDF::TableExtract->new();
    $te->load_pdf($filename);
    $te->parse;  # parse the pdf for tables
    my @tables = $te->tables;

    return @tables;
}

# main program
my $pdf_file = 'example.pdf';  # replace with your pdf file
my ($author, $title, $date) = extract_metadata($pdf_file);
my @tables = extract_tables($pdf_file);

# print metadata
print "Author: $author\n";
print "Title: $title\n";
print "Date: $date\n";

# print tables
foreach my $table (@tables) {
    print "Table:\n";
    print $table->as_csv;  # assuming you want the table as a csv string
    print "\n";
}
